ana\",\"fontSize\":\"16px\",\"fontWeight\":\"normal\",\"textAlign\":\"center\"}}},{\"type\":\"text\",\"text\":\"<p><span class=\\\"prismjs css-1xfvm4v\\\" data-code-lang=\\\"\\\" data-ds--code--code-block=\\\"\\\">If you\'re no longer interested, that\'s completely fine. You don\'t need to take any action. Our system will automatically unsubscribe you soon from all of our future content.<\\/span><\\/p>\"}]}]},{\"type\":\"container\",\"columnLayout\":false,\"orientation\":\"horizontal\",\"image\":{\"src\":null,\"display\":\"scale\"},\"styles\":{\"block\":{\"backgroundColor\":\"#ffffff\"}},\"blocks\":[{\"type\":\"container\",\"columnLayout\":false,\"orientation\":\"vertical\",\"image\":{\"src\":null,\"display\":\"scale\"},\"styles\":{\"block\":{\"backgroundColor\":\"transparent\"}},\"blocks\":[{\"type\":\"text\",\"text\":\"<p><strong><em><\\/em><\\/strong><\\/p><p><strong><em>The MailPoet Team<\\/em><\\/strong><\\/p>\"},{\"type\":\"footer\",\"text\":\"<p><a href=\\\"[link:subscription_unsubscribe_url]\\\">Unsubscribe<\\/a> | <a href=\\\"[link:subscription_manage_url]\\\">Manage subscription<\\/a><br \\/>Add your postal address here!<\\/p>\",\"styles\":{\"block\":{\"backgroundColor\":\"transparent\"},\"text\":{\"fontColor\":\"#222222\",\"fontFamily\":\"Arial\",\"fontSize\":\"12px\",\"textAlign\":\"left\"},\"link\":{\"fontColor\":\"#6cb7d4\",\"textDecoration\":\"none\"}}}]}]}]},\"globalStyles\":{\"text\":{\"fontColor\":\"#000000\",\"fontFamily\":\"Arial\",\"fontSize\":\"15px\",\"lineHeight\":\"1.6\"},\"h1\":{\"fontColor\":\"#111111\",\"fontFamily\":\"Trebuchet MS\",\"fontSize\":\"30px\",\"lineHeight\":\"1.6\"},\"h2\":{\"fontColor\":\"#222222\",\"fontFamily\":\"Trebuchet MS\",\"fontSize\":\"24px\",\"lineHeight\":\"1.6\"},\"h3\":{\"fontColor\":\"#333333\",\"fontFamily\":\"Trebuchet MS\",\"fontSize\":\"22px\",\"lineHeight\":\"1.6\"},\"link\":{\"fontColor\":\"#21759B\",\"textDecoration\":\"underline\"},\"wrapper\":{\"backgroundColor\":\"#ffffff\"},\"body\":{\"backgroundColor\":\"#ffffff\"}}}','https://ps.w.org/mailpoet/assets/newsletter-templates/confirm-interest-before-deactivation/thumbnail.20211026.jpg',NULL,1,NULL,'2026-06-04 21:24:24');
INSERT INTO `wp_mailpoet_newsletter_templates` VALUES (76,0,'Confirm your interest or unsubscribe','[\"re_engagement\",\"all\"]','','{\"content\":{\"type\":\"container\",\"columnLayout\":false,\"orientation\":\"vertical\",\"image\":{\"src\":null,\"display\":\"scale\"},\"styles\":{\"block\":{\"backgroundColor\":\"transparent\"}},\"blocks\":[{\"type\":\"container\",\"columnLayout\":false,\"orientation\":\"horizontal\",\"image\":{\"src\":null,\"display\":\"scale\"},\"styles\":{\"block\":{\"backgroundColor\":\"#ffffff\"}},\"blocks\":[{\"type\":\"container\",\"columnLayout\":false,\"orientation\":\"vertical\",\"image\":{\"src\":null,\"display\":\"scale\"},\"styles\":{\"block\":{\"backgroundColor\":\"transparent\"}},\"blocks\":[{\"type\":\"spacer\",\"styles\":{\"block\":{\"backgroundColor\":\"transparent\",\"height\":\"30px\"}}},{\"type\":\"image\",\"link\":\"\",\"src\":\"https:\\/\\/accepteddevtask.local\\/wp-content\\/plugins\\/mailpoet\\/assets\\/img\\/blank_templates\\/fake-logo.png\",\"alt\":\"Fake logo\",\"fullWidth\":false,\"width\":\"598px\",\"height\":\"71px\",\"styles\":{\"block\":{\"textAlign\":\"center\"}}},{\"type\":\"text\",\"text\":\"<p style=\\\"text-align: left;\\\">Hi [subscriber:firstname | default:there],<\\/p><p style=\\\"text-align: left;\\\"><\\/p>\\n                                  <p style=\\\"text-align: left;\\\"><span>It\'s been a while since you opened our emails. If you have changed your mind since you subscribed and are no longer interested, we get it! We won\'t make it hard for you, so feel free to unsubscribe right away.&nbsp;<\\/span><\\/p><p style=\\\"text-align: left;\\\"><\\/p>\\n                                  <p style=\\\"text-align: left;\\\"><a href=\\\"[link:subscription_unsubscribe_url]\\\">Unsubscribe me!<\\/a><\\/p><p style=\\\"text-align: left;\\\"><\\/p>\\n                                  <p style=\\\"text-align: left;\\\">(When you unsubscribe, you\'ll stop receiving all future emails from us.)<\\/p><p style=\\\"text-align: left;\\\"><\\/p>\\n                                  <p style=\\\"text-align: left;\\\"><span>On the other hand, if you like our emails and want to keep receiving them, please <strong>reconfirm your subscription by clicking the big button below<\\/strong>.<\\/span><\\/p>\"},{\"type\":\"button\",\"text\":\"Yes, keep me subscribed!\",\"url\":\"[link:subscription_re_engage_url]\",\"styles\":{\"block\":{\"backgroundColor\":\"#2ea1cd\",\"borderColor\":\"#0074a2\",\"borderWidth\":\"1px\",\"borderRadius\":\"5px\",\"borderStyle\":\"solid\",\"width\":\"288px\",\"lineHeight\":\"40px\",\"fontColor\":\"#ffffff\",\"fontFamily\":\"Verdana\",\"fontSize\":\"16px\",\"fontWeight\":\"normal\",\"textAlign\":\"center\"}}}]}]},{\"type\":\"container\",\"columnLayout\":false,\"orientation\":\"horizontal\",\"image\":{\"src\":null,\"display\":\"scale\"},\"styles\":{\"block\":{\"backgroundColor\":\"#ffffff\"}},\"blocks\":[{\"type\":\"container\",\"columnLayout\":false,\"orientation\":\"vertical\",\"image\":{\"src\":null,\"display\":\"scale\"},\"styles\":{\"block\":{\"backgroundColor\":\"transparent\"}},\"blocks\":[{\"type\":\"text\",\"text\":\"<p><strong><em><\\/em><\\/strong><\\/p><p><strong><em>The MailPoet Team<\\/em><\\/strong><\\/p>\"},{\"type\":\"footer\",\"text\":\"<p><a href=\\\"[link:subscription_unsubscribe_url]\\\">Unsubscribe<\\/a> | <a href=\\\"[link:subscription_manage_url]\\\">Manage your subscription<\\/a><br \\/>Add your postal address here!<\\/p>\",\"styles\":{\"block\":{\"backgroundColor\":\"transparent\"},\"text\":{\"fontColor\":\"#222222\",\"fontFamily\":\"Arial\",\"fontSize\":\"12px\",\"textAlign\":\"left\"},\"link\":{\"fontColor\":\"#6cb7d4\",\"textDecoration\":\"none\"}}}]}]}]},\"globalStyles\":{\"text\":{\"fontColor\":\"#000000\",\"fontFamily\":\"Arial\",\"fontSize\":\"15px\",\"lineHeight\":\"1.6\"},\"h1\":{\"fontColor\":\"#111111\",\"fontFamily\":\"Trebuchet MS\",\"fontSize\":\"30px\",\"lineHeight\":\"1.6\"},\"h2\":{\"fontColor\":\"#222222\",\"fontFamily\":\"Trebuchet MS\",\"fontSize\":\"24px\",\"lineHeight\":\"1.6\"},\"h3\":{\"fontColor\":\"#333333\",\"fontFamily\":\"Trebuchet MS\",\"fontSize\":\"22px\",\"lineHeight\":\"1.6\"},\"link\":{\"fontColor\":\"#21759B\",\"textDecoration\":\"underline\"},\"wrapper\":{\"backgroundColor\":\"#ffffff\"},\"body\":{\"backgroundColor\":\"#ffffff\"}}}','https://ps.w.org/mailpoet/assets/newsletter-templates/confirm-interest-or-unsubscribe/thumbnail.20211026.jpg',NULL,1,NULL,'2026-06-04 21:24:24');
INSERT INTO `wp_mailpoet_newsletter_templates` VALUES (77,0,'Birthday Celebration','[\"woocommerce\",\"all\"]','','{\"content\":{\"type\":\"container\",\"orientation\":\"vertical\",\"styles\":{\"block\":{\"backgroundColor\":\"transparent\"}},\"blocks\":[{\"type\":\"container\",\"orientation\":\"horizontal\",\"styles\":{\"block\":{\"backgroundColor\":\"#fec8c1\"}},\"blocks\":[{\"type\":\"container\",\"orientation\":\"vertical\",\"styles\":{\"block\":{\"backgroundColor\":\"transparent\"}},\"blocks\":[{\"type\":\"header\",\"text\":\"<p><a href=\\\"[link:newsletter_view_in_browser_url]\\\">View this in your browser.<\\/a><\\/p>\",\"styles\":{\"block\":{\"backgroundColor\":\"transparent\"},\"text\":{\"fontColor\":\"#888888\",\"fontFamily\":\"Arial\",\"fontSize\":\"12px\",\"textAlign\":\"center\"},\"link\":{\"fontColor\":\"#e6527a\",\"textDecoration\":\"underline\"}}},{\"type\":\"spacer\",\"styles\":{\"block\":{\"backgroundColor\":\"transparent\",\"height\":\"20px\"}}},{\"type\":\"image\",\"link\":\"\",\"src\":\"https:\\/\\/ps.w.org\\/mailpoet\\/assets\\/newsletter-templates\\/birthday-celebration\\/celebration.jpg\",\"alt\":\"Birthday celebration\",\"fullWidth\":true,\"width\":\"1320px\",\"height\":\"578px\",\"styles\":{\"block\":{\"textAlign\":\"center\"}}},{\"type\":\"spacer\",\"styles\":{\"block\":{\"backgroundColor\":\"transparent\",\"height\":\"25px\"}}},{\"type\":\"text\",\"text\":\"<h1 style=\\\"text-align: center;\\\"><span style=\\\"color: #e6527a;\\\">Happy Birthday, [subscriber:firstname | default:friend]!<\\/span><\\/h1>\"},{\"type\":\"text\",\"text\":\"<p style=\\\"text-align: center; font-size: 17px;\\\"><span style=\\\"color: #555555;\\\">It\'s your special day and we want to celebrate with you!<\\/span><\\/p>\"},{\"type\":\"spacer\",\"styles\":{\"block\":{\"backgroundColor\":\"transparent\",\"height\":\"25px\"}}},{\"type\":\"text\",\"text\":\"<p style=\\\"text-align: center; font-size: 15px;\\\"><span style=\\\"color: #555555;\\\">To make your day even sweeter, here\'s a special treat just for you.<\\/span><\\/p>\"},{\"type\":\"spacer\",\"styles\":{\"block\":{\"backgroundColor\":\"transparent\",\"height\":\"15px\"}}},{\"type\":\"coupon\",\"amount\":20,\"amountMax\":100,\"discountType\":\"percent\",\"expiryDay\":14,\"usageLimit\":\"\",\"usageLimitPerUser\":\"1\",\"minimumAmount\":\"\",\"maximumAmount\":\"\",\"emailRestrictions\":\"\",\"productIds\":[],\"excludedProductIds\":[],\"productCategoryIds\":[],\"excludedProductCategoryIds\":[],\"styles\":{\"block\":{\"backgroundColor\":\"#e6527a\",\"borderColor\":\"#e6527a\",\"borderWidth\":\"0px\",\"borderRadius\":\"5px\",\"borderStyle\":\"solid\",\"width\":\"240px\",\"lineHeight\":\"50px\",\"fontColor\":\"#ffffff\",\"fontFamily\":\"Georgia\",\"fontSize\":\"24px\",\"fontWeight\":\"bold\",\"textAlign\":\"center\"}},\"source\":\"createNew\",\"code\":\"XXXX-XXXXXXX-XXXX\"},{\"type\":\"text\",\"text\":\"<p style=\\\"text-align: center; font-size: 13px;\\\"><span style=\\\"color: #888888;\\\">Use this code for 20% off your next order.<\\/span><\\/p>\"},{\"type\":\"spacer\",\"styles\":{\"block\":{\"backgroundColor\":\"transparent\",\"height\":\"20px\"}}},{\"type\":\"button\",\"text\":\"Shop Now\",\"url\":\"[site:homepage_url]\",\"styles\":{\"block\":{\"backgroundColor\":\"#ff6b6b\",\"borderColor\":\"#e55a5a\",\"borderWidth\":\"0px\",\"borderRadius\":\"30px\",\"borderStyle\":\"solid\",\"width\":\"260px\",\"lineHeight\":\"50px\",\"fontColor\":\"#ffffff\",\"fontFamily\":\"Georgia\",\"fontSize\":\"18px\",\"fontWeight\":\"bold\",\"textAlign\":\"center\"}}},{\"type\":\"spacer\",\"styles\":{\"block\":{\"backgroundColor\":\"transparent\",\"height\":\"30px\"}}}]}]},{\"type\":\"container\",\"orientation\":\"horizontal\",\"styles\":{\"block\":{\"backgroundColor\":\"#fec8c1\"}},\"blocks\":[{\"type\":\"container\",\"orientation\":\"vertical\",\"styles\":{\"block\":{\"backgroundColor\":\"transparent\"}},\"blocks\":[{\"type\":\"social\",\"iconSet\":\"official\",\"icons\":[{\"type\":\"socialIcon