:13:\"allow-dismiss\";b:0;}i:7;a:9:{s:4:\"slug\";s:42:\"orders-list-empty-body-table-rate-shipping\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:19:\"table-rate-shipping\";s:4:\"icon\";s:101:\"https://woocommerce.com/wp-content/uploads/2012/07/Table_Rate_Shipping_icon-marketplace-160x160-2.png\";s:5:\"title\";s:19:\"Table Rate Shipping\";s:4:\"copy\";s:123:\"Advanced, flexible shipping. Define multiple shipping rates based on location, price, weight, shipping class or item count.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:53:\"https://woocommerce.com/products/table-rate-shipping/\";s:9:\"is_pinned\";b:1;}i:8;a:9:{s:4:\"slug\";s:56:\"orders-list-empty-body-conditional-shipping-and-payments\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:33:\"conditional-shipping-and-payments\";s:4:\"icon\";s:111:\"https://woocommerce.com/wp-content/uploads/2015/03/Conditional_Shipping_Payments_icon-marketplace-160x160-1.png\";s:5:\"title\";s:33:\"Conditional Shipping and Payments\";s:4:\"copy\";s:91:\"Use conditional logic to restrict the shipping and payment options available on your store.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:67:\"https://woocommerce.com/products/conditional-shipping-and-payments/\";s:9:\"is_pinned\";b:1;}i:9;a:9:{s:4:\"slug\";s:40:\"orders-list-empty-body-shipment-tracking\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:17:\"shipment-tracking\";s:4:\"icon\";s:99:\"https://woocommerce.com/wp-content/uploads/2012/05/Shipment_Tracking_icon-marketplace-160x160-2.png\";s:5:\"title\";s:17:\"Shipment Tracking\";s:4:\"copy\";s:49:\"Add shipment tracking information to your orders.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:51:\"https://woocommerce.com/products/shipment-tracking/\";s:9:\"is_pinned\";b:1;}i:10;a:8:{s:4:\"slug\";s:67:\"orders-list-empty-body-ph-hide-shipping-methods-and-rate-adjustment\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:44:\"ph-hide-shipping-methods-and-rate-adjustment\";s:4:\"icon\";s:72:\"https://woocommerce.com/wp-content/uploads/2026/04/hide-shipping-160.jpg\";s:5:\"title\";s:42:\"PH Hide Shipping Methods & Rate Adjustment\";s:4:\"copy\";s:154:\"Conditionally hide shipping methods and adjust shipping rates in WooCommerce based on products, cart conditions, locations, user roles, coupons, and more.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:78:\"https://woocommerce.com/products/ph-hide-shipping-methods-and-rate-adjustment/\";}i:11;a:8:{s:4:\"slug\";s:63:\"orders-list-empty-body-conditional-shipping-and-payment-methods\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:40:\"conditional-shipping-and-payment-methods\";s:4:\"icon\";s:62:\"https://woocommerce.com/wp-content/uploads/2026/01/160x160.png\";s:5:\"title\";s:50:\"Extendons Conditional Shipping and Payment Methods\";s:4:\"copy\";s:136:\"Control shipping and payment methods at checkout using rules based on products, cart totals, user roles, location, and order conditions.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:74:\"https://woocommerce.com/products/conditional-shipping-and-payment-methods/\";}i:12;a:8:{s:4:\"slug\";s:42:\"orders-list-empty-body-order-delivery-date\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:19:\"order-delivery-date\";s:4:\"icon\";s:65:\"https://woocommerce.com/wp-content/uploads/2025/02/ordd-png-1.png\";s:5:\"title\";s:19:\"Order Delivery Date\";s:4:\"copy\";s:132:\"Let your customers choose a desired delivery date & time slots (set by you) for their local pickup or delivery on the checkout page.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:53:\"https://woocommerce.com/products/order-delivery-date/\";}i:13;a:8:{s:4:\"slug\";s:60:\"orders-list-empty-body-pdf-packing-slips-and-invoice-builder\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:37:\"pdf-packing-slips-and-invoice-builder\";s:4:\"icon\";s:111:\"https://woocommerce.com/wp-content/uploads/2024/12/pdf_packing_slips_and_invoice_builder_marketplace_icon_.webp\";s:5:\"title\";s:37:\"PDF Packing Slips and Invoice Builder\";s:4:\"copy\";s:328:\"The PDF Packing Slips and Invoice Builder plugin for WooCommerce automates creating and managing essential e-commerce documents like invoices, packing slips, and credit notes. It offers customizable templates, automatic PDF generation, and seamless integration with WooCommerce for improved efficiency and professional branding.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:71:\"https://woocommerce.com/products/pdf-packing-slips-and-invoice-builder/\";}i:14;a:8:{s:4:\"slug\";s:34:\"orders-list-empty-body-pdf-invoice\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:11:\"pdf-invoice\";s:4:\"icon\";s:66:\"https://woocommerce.com/wp-content/uploads/2026/02/pdf-invoice.png\";s:5:\"title\";s:41:\"PDF Invoice, Packing Slips & Credit Notes\";s:4:\"copy\";s:488:\"Auto-generate WooCommerce PDF invoices, packing slips, and credit notes for every order. Attach PDFs to order emails, let customers download invoices from My Account, and customize templates with your logo, brand colors, and company details. Supports advanced numbering with placeholders ({order_id}, {date}, prefix, suffix), automatic credit notes on refunds, and bulk export. The complete WooCommerce invoice plugin for store owners who need professional, automated order documentation.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:45:\"https://woocommerce.com/products/pdf-invoice/\";}i:15;a:8:{s:4:\"slug\";s:58:\"orders-list-empty-body-multiple-shipping-boxes-per-product\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:35:\"multiple-shipping-boxes-per-product\";s:4:\"icon\";s:106:\"https://woocommerce.com/wp-content/uploads/2025/01/Add-Multiple-Shipping-Boxes-for-a-Single-Product-01.png\";s:5:\"title\";s:35:\"Multiple Shipping Boxes Per Product\";s:4:\"copy\";s:140:\"Easily manage products that need shipping in multiple boxes. Assign multiple boxes to each product to ensure accurate shipping calculations.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:69:\"https://woocommerce.com/products/multiple-shipping-boxes-per-product/\";}i:16;a:9:{s:4:\"slug\";s:42:\"product-edit-meta-tab-body-product-add-ons\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:15:\"product-add-ons\";s:4:\"icon\";s:96:\"https://woocommerce.com/wp-content/uploads/2013/05/Product_Addons_icon-marketplace-160x160-2.png\";s:5:\"title\";s:15:\"Product Add-Ons\";s:4:\"copy\";s:94:\"Offer add-ons like gift wrapping, special messages or other special options for your products.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:49:\"https://woocommerce.com/products/product-add-ons/\";s:9:\"is_pinned\";b:1;}i:17;a:9:{s:4:\"slug\";s:42:\"product-edit-meta-tab-body-product-bundles\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:15:\"product-bundles\";s:4:\"icon\";s:97:\"https://woocommerce.com/wp-content/uploads/2012/07/Product_Bundles_icon-marketplace-160x160-2.png\";s:5:\"title\";s:15:\"Product Bundles\";s:4:\"copy\";s:84:\"Offer personalized product bundles, bulk discount packages, and assembled products.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:49:\"https://woocommerce.com/products/product-bundles/\";s:9:\"is_pinned\";b:1;}i:18;a:9:{s:4:\"slug\";s:47:\"product-edit-meta-tab-body-woocommerce-bookings\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:20:\"woocommerce-bookings\";s:4:\"icon\";s:90:\"https://woocommerce.com/wp-content/uploads/2014/05/Bookings_icon-marketplace-160x160-1.png\";s:5:\"title\";s:20:\"WooCommerce Bookings\";s:4:\"copy\";s:101:\"Allow customers to book appointments, make reservations, or rent equipment without leaving your site.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:54:\"https://woocommerce.com/products/woocommerce-bookings/\";s:9:\"is_pinned\";b:1;}i:19;a:9:{s:4:\"slug\";s:52:\"product-edit-meta-tab-body-woocommerce-subscriptions\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:25:\"woocommerce-subscriptions\";s:4:\"icon\";s:99:\"https://woocommerce.com/wp-content/uploads/2012/09/Woo_Subscriptions_icon-marketplace-160x160-2.png\";s:5:\"title\";s:25:\"WooCommerce Subscriptions\";s:4:\"copy\";s:98:\"Let customers subscribe to your products or services and pay on a weekly, monthly or annual basis.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:59:\"https://woocommerce.com/products/woocommerce-subscriptions/\";s:9:\"is_pinned\";b:1;}i:20;a:9:{s:4:\"slug\";s:45:\"product-edit-meta-tab-body-composite-products\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:18:\"composite-products\";s:4:\"icon\";s:100:\"https://woocommerce.com/wp-content/uploads/2013/06/Composite_Products_icon-marketplace-160x160-1.png\";s:5:\"title\";s:18:\"Composite Products\";s:4:\"copy\";s:85:\"Create product kit builders and custom product configurators using existing products.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:52:\"https://woocommerce.com/products/composite-products/\";s:9:\"is_pinned\";b:1;}i:21;a:8:{s:4:\"slug\";s:38:\"product-edit-meta-tab-body-b2b-pricing\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:11:\"b2b-pricing\";s:4:\"icon\";s:72:\"https://woocommerce.com/wp-content/uploads/2026/03/WooCommerce-B2B-2.png\";s:5:\"title\";s:11:\"B2B Pricing\";s:4:\"copy\";s:399:\"Complete WooCommerce B2B pricing and wholesale solution. Create role-based pricing, tiered discounts, fixed wholesale prices, and tax exemptions for wholesale buyers, distributors, and VIP customers. Control price visibility by user role, automate customer approval workflows, and apply rules by product, category, or country. Supports unlimited pricing rules, dynamic pricing, and custom B2B roles.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:45:\"https://woocommerce.com/products/b2b-pricing/\";}i:22;a:8:{s:4:\"slug\";s:58:\"product-edit-meta-tab-body-bulk-order-form-for-woocommerce\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:31:\"bulk-order-form-for-woocommerce\";s:4:\"icon\";s:88:\"https://woocommerce.com/wp-content/uploads/2020/04/Bulk-Order-Form-For-WooCommerce-3.png\";s:5:\"title\";s:32:\"Bulk Order – B2B Product Table\";s:4:\"copy\";s:115:\"Revolutionize product tables through Bulk Order Form for WooCommerce. Add sorting, search, pagination, and filters.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:65:\"https://woocommerce.com/products/bulk-order-form-for-woocommerce/\";}i:23;a:8:{s:4:\"slug\";s:59:\"product-edit-meta-tab-body-deposit-and-partial-payment-plan\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:32:\"deposit-and-partial-payment-plan\";s:4:\"icon\";s:82:\"https://woocommerce.com/wp-content/uploads/2026/05/deposit-and-partial-payment.png\";s:5:\"title\";s:32:\"Deposit and Partial Payment Plan\";s:4:\"copy\";s:208:\"Offer deposits, installments, and flexible payment plans in WooCommerce. Reduce cart abandonment on premium products with rule-based schedules, automated installment charging, and built-in customer reminders.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:66:\"https://woocommerce.com/products/deposit-and-partial-payment-plan/\";}i:24;a:8:{s:4:\"slug\";s:54:\"product-edit-meta-tab-body-invoice-payment-option-free\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:27:\"invoice-payment-option-free\";s:4:\"icon\";s:78:\"https://woocommerce.com/wp-content/uploads/2024/10/invoice-payment-gateway.png\";s:5:\"title\";s:27:\"Invoice Payment Option Free\";s:4:\"copy\";s:118:\"Add an invoice payment method to your checkout allowing your customers place order without making payment at checkout.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:61:\"https://woocommerce.com/products/invoice-payment-option-free/\";}i:25;a:8:{s:4:\"slug\";s:45:\"product-edit-meta-tab-body-payment-plan-suite\";s:7:\"context\";s:26:\"product-edit-meta-tab-body\";s:7:\"product\";s:18:\"payment-plan-suite\";s:4:\"icon\";s:80:\"https://woocommerce.com/wp-content/uploads/2023/02/payment-plan-icon-new-160.png\";s:5:\"title\";s:18:\"Payment Plan Suite\";s:4:\"copy\";s:61:\"Offer customizable payment plans and reduce cart abandonment.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:52:\"https://woocommerce.com/products/payment-plan-suite/\";}}s:7:\"updated\";i:1780608128;}','off');
